//! bench-hope-jar-e8 — throughput + latency of the E_8 Hope Jar.
//!
//! Release-only numbers (build with --release). Reports the latent-key
//! regeneration rate (the hot path — keys are never materialised), the
//! O(1) predict() point query, rknot codec cost, and the disk/cap win
//! versus the Monster jar.

use distributed_inference::hope_jar_e8::{HopeJarE8, CHARGE_SEEDS, E8_WEYL_ORDER};
use std::hint::black_box;
use std::time::Instant;

fn main() {
    // ── construction (builds the 240-root well-order: enumerate + sort) ──
    let t = Instant::now();
    let j0 = black_box(HopeJarE8::new());
    let new_us = t.elapsed().as_nanos() as f64 / 1000.0;
    black_box(&j0);

    // ── charge (170 seeds; keys stay latent) ──
    let seeds: Vec<u64> = (0..CHARGE_SEEDS as u64)
        .map(|i| i.wrapping_mul(2654435761).wrapping_add(1))
        .collect();
    let mut jar = HopeJarE8::new();
    let t = Instant::now();
    jar.charge_from_seeds(&seeds, 0);
    let charge_us = t.elapsed().as_nanos() as f64 / 1000.0;
    assert!(jar.is_sealed());

    // ── discharge throughput (latent key regeneration) ──
    // Walk distinct (phase, lane) slots; sum every regenerated carrier.
    let n_slots = 2000usize;
    let mut keys = 0u64;
    let mut acc = 0u64;
    let t = Instant::now();
    for s in 0..n_slots {
        let phase = (s % 30) as u8;
        let lane = ((s / 30) % 240) as u8;
        for k in jar.discharge_iter(phase, lane) {
            acc ^= k;
            keys += 1;
        }
    }
    let dis_dur = t.elapsed();
    let keys_per_sec = keys as f64 / dis_dur.as_secs_f64();
    black_box(acc);

    // ── full-slot latency (96768 carriers) ──
    let runs = 200;
    let t = Instant::now();
    let mut acc2 = 0u64;
    for r in 0..runs {
        let v = jar.discharge((r % 30) as u8, ((r * 7) % 240) as u8);
        acc2 ^= v.first().copied().unwrap_or(0) ^ (v.len() as u64);
    }
    let slot_us = t.elapsed().as_nanos() as f64 / runs as f64 / 1000.0;
    black_box(acc2);

    // ── predict() O(1) point query ──
    let n_pred = 20_000_000u64;
    let mut acc3 = 0u64;
    let t = Instant::now();
    for i in 0..n_pred {
        acc3 ^= jar.predict(i.wrapping_mul(2654435761));
    }
    let pred_dur = t.elapsed();
    let pred_per_sec = n_pred as f64 / pred_dur.as_secs_f64();
    let pred_ns = pred_dur.as_nanos() as f64 / n_pred as f64;
    black_box(acc3);

    // ── rknot codec ──
    let t = Instant::now();
    let bytes = jar.encode_rknot();
    let enc_us = t.elapsed().as_nanos() as f64 / 1000.0;
    let enc_len = bytes.len();
    let t = Instant::now();
    let dec = HopeJarE8::decode_rknot(&bytes).expect("decode");
    let dec_us = t.elapsed().as_nanos() as f64 / 1000.0;
    black_box(dec.capacity());

    // ── load a real charged jar from disk if present ──
    let disk = std::fs::read("rknots/hope-jar-e8.rknot").ok();
    let load = disk.as_ref().and_then(|d| {
        let t = Instant::now();
        let j = HopeJarE8::decode_rknot(d);
        j.map(|jj| {
            (
                t.elapsed().as_nanos() as f64 / 1000.0,
                d.len(),
                jj.seeds_loaded(),
            )
        })
    });

    // ── extrapolations ──
    let full_battery_s = E8_WEYL_ORDER as f64 / keys_per_sec;
    let monster_disk = 1_575_087f64;
    let disk_ratio = monster_disk / enc_len as f64;
    let cap_ratio = E8_WEYL_ORDER as f64 / 196_884.0;

    println!("=== Hope Jar E8 benchmark (release, warm) ===");
    println!(
        "capacity            : {} keys (|W(E8)|), LATENT",
        E8_WEYL_ORDER
    );
    println!(
        "construction (new)  : {:.2} us  (enumerate 240 roots + sort well-order)",
        new_us
    );
    println!("charge (170 seeds)  : {:.2} us", charge_us);
    println!();
    println!("-- discharge (latent key regeneration) --");
    println!(
        "throughput          : {:.1} M keys/s ({:.0} keys in {:.2} ms)",
        keys_per_sec / 1e6,
        keys as f64,
        dis_dur.as_secs_f64() * 1000.0
    );
    println!("full slot (96768)   : {:.2} us/slot", slot_us);
    println!("per-key             : {:.3} ns", 1e9 / keys_per_sec);
    println!();
    println!("-- predict() O(1) point query --");
    println!("throughput          : {:.1} M ops/s", pred_per_sec / 1e6);
    println!("latency             : {:.3} ns/query", pred_ns);
    println!();
    println!("-- rknot codec --");
    println!(
        "encode              : {:.2} us -> {} bytes",
        enc_us, enc_len
    );
    println!("decode              : {:.2} us", dec_us);
    if let Some((load_us, len, seeds)) = load {
        println!(
            "load rain jar       : {:.2} us ({} bytes, {} seeds, from disk)",
            load_us, len, seeds
        );
    } else {
        println!("load rain jar       : (rknots/hope-jar-e8.rknot not found from cwd)");
    }
    println!();
    println!("-- vs Monster jar (196884 keys, 1.5 MB on disk) --");
    println!("capacity ratio      : {:.0}x more keys", cap_ratio);
    println!(
        "disk ratio          : {:.0}x smaller ({} B vs {} B) — keys latent",
        disk_ratio, enc_len, monster_disk as u64
    );
    println!(
        "materialise full cap: {:.1} s to regenerate all {} keys (never done in practice)",
        full_battery_s, E8_WEYL_ORDER
    );
    println!();
    println!("sanity blackbox: {}", acc ^ acc2 ^ acc3);
}
